#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
   using namespace sqlgen;
   using namespace sqlgen::literals;

   // Connect to SQLite database
   auto conn_result = sqlite::connect("test_db.sqlite");
   if (!conn_result) {
       return false;
   }
   auto conn = std::move(conn_result).value();

   // Drop table if exists and create new table
   auto drop_result = drop_table<Product>(conn) | if_exists;
   if (!drop_result) {
       return false;
   }

   auto create_result = create_table<Product>(conn);
   if (!create_result) {
       return false;
   }

   // Begin transaction
   auto tx_result = conn.begin_transaction();
   if (!tx_result) {
       return false;
   }
   auto tx = std::move(tx_result).value();

   // Insert all products
   bool all_success = true;
   for (const auto& product : products) {
       auto insert_result = insert_into<Product>(tx, product);
       if (!insert_result) {
           all_success = false;
           break;
       }
   }

   // Commit if all inserts succeeded, otherwise rollback
   if (all_success) {
       auto commit_result = tx.commit();
       return commit_result.has_value();
   } else {
       auto rollback_result = tx.rollback();
       return false;
   }
}

}  // namespace batch_insert_products
