```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Use a transaction to ensure safety
  db.begin_transaction();

  try {
    // Delete users who have not logged in since 2025-01-01
    using namespace sqlgen::literals;

    // Build the DELETE query using sqlgen's fluent API
    auto query = sqlgen::remove<User>().where("last_login"_c < sqlgen::date("2025-01-01"));

    // Execute the query and get the number of affected rows
    int affected_rows = db.execute(query);

    // Commit the transaction
    db.commit();

    // Return the number of affected rows (operation result)
    return affected_rows;
  } catch (...) {
    // Rollback the transaction in case of any error
    db.rollback();
    throw; // Re-throw the exception
  }
}

} // namespace delete_inactive_users
```

