```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Create User and Post tables
    sqlgen::syncSchema(db, User{});
    sqlgen::syncSchema(db, Post{});

    // Query active users who posted between 2025-12-01 and 2025-12-31
    auto active_users = sqlgen::query<ActiveUser>(db, [](const User& u, const Post& p) {
        return sqlgen::select(u.user_id, u.username)
            .from(u)
            .join(p).on(u.user_id == p.user_id)
            .where(p.created_at >= sqlgen::date("2025-12-01") && 
                   p.created_at <= sqlgen::date("2025-12-31"));
    });

    return active_users;
}

}  // namespace query_active_users_posts
```

