Looking at the provided code fragments and the requirements, I need to implement the `query_employee_hierarchy` function using the `sqlgen` library. Based on the examples, I can see how to use the library for querying and joining tables.

Here's the complete implementation:

```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create aliases for the self-join
    auto e1 = alias<Employee>("e1");
    auto e2 = alias<Employee>("e2");

    // Build the query using sqlgen's fluent interface
    const auto query = 
        read<decltype(e1)>() |
        left_join<decltype(e2)>(e1.manager_id, e2.emp_id) |
        select(e1.name, e2.name);

    // Execute the query against the SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");
    return conn.query<EmployeeManager>(query);
}

}  // namespace query_employee_hierarchy
```

