namespace query_high_value_orders {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  sqlgen::sqlite::Connection connection("test_db.sqlite");

  auto results = sqlgen::sqlite::select<OrderView>()
      .from<Order>("o")
      .join<Customer>("c").on("o.customer_id = c.customer_id")
      .where("o.total_amount > 1000")
      .order_by("o.total_amount DESC")
      .execute(connection);

  return results;
}

}  // namespace query_high_value_orders
```

