  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Build the query using sqlgen
    auto query = read<std::vector<ProductSalesReport>> |
                 join<Sale>(on(Product::product_id == Sale::product_id)) |
                 group_by(Product::category) |
                 having(sum(Sale::amount) > 5000);

    // Execute the query
    auto results = conn | query;

    // Convert to CategoryReport format
    std::vector<CategoryReport> reports;
    for (const auto& result : results) {
        reports.push_back(CategoryReport{
            .category = result.category,
            .total_qty = result.total_qty,
            .total_amt = result.total_amt
        });
