Here's the complete implementation:

```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the database
    auto result = sqlite::connect("test_db.sqlite")
        .and_then([&filters](auto conn) {
            // Start with base SELECT query
            auto query = select<Book>;

            // Add WHERE clauses dynamically based on non-null parameters
            if (filters.title_keyword) {
                query = query | where("title"_c.like("%" + *filters.title_keyword + "%"));
            }

            if (filters.min_year) {
                query = query | where("year"_c >= *filters.min_year);
            }

            if (filters.genre) {
                query = query | where("genre"_c == *filters.genre);
            }

            if (filters.max_price) {
                query = query | where("price"_c <= *filters.max_price);
            }

            return conn.and_then(query);
        })
        .and_then(read<std::vector<Book>>);

    // Return the result or empty vector if there was an error
    return result.value_or(std::vector<Book>{});
}

}  // namespace query_search_books_by_criteria
```

Key aspects of this implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database.

2. **Dynamic Query Building**: Starts with a base `select<Book>` query and conditionally adds WHERE clauses using the pipe operator `|` with `where` conditions.

3. **Filter Handling**:
   - For `title_keyword`: Uses `LIKE` with wildcards for partial matching
   - For `min_year`: Uses `>=` comparison operator
   - For `genre`: Uses `==` for exact matching
   - For `max_price`: Uses `<=` comparison operator

4. **Conditional Logic**: Each filter is only added to the query if the optional parameter has a value (not null).

5. **Result Handling**: Uses `value_or` to return an empty vector if the database operation fails.

The implementation follows the patterns shown in the code fragments, using the `sqlgen` library's fluent interface for building SQL queries with compile-time type safety.

