  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    try {
      // Connect to SQLite database
      sqlgen::SQLite db("test_db.sqlite");

      // Create Product table
      db.create_table<Product>();

      // Create indexes with IF NOT EXISTS logic
      db.execute(R"(
        CREATE INDEX IF NOT EXISTS idx_product_category ON Product(category);
      )");

      db.execute(R"(
        CREATE UNIQUE INDEX IF NOT EXISTS idx_product_sku ON Product(sku);
      )");

      db.execute(R"(
