```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Start transaction
  auto transaction_result = conn.transaction([&]() -> sqlgen::Result<bool> {
    // Check if sender has sufficient funds
    auto sender_result = sqlgen::read<Account>(
        "account_id"_c == from_account_id);
    auto sender = conn.execute(sender_result);
    if (!sender || sender->empty()) {
      return sqlgen::Error("Sender account not found");
    }

    if (sender->front().balance < amount) {
      return sqlgen::Error("Insufficient funds");
    }

    // Update sender's balance (deduct amount)
    auto update_sender = sqlgen::update<Account>()
        .set("balance"_c = "balance"_c - amount)
        .where("account_id"_c == from_account_id);

    auto sender_update_result = conn.execute(update_sender);
    if (!sender_update_result) {
      return sender_update_result.error();
    }

    // Update receiver's balance (add amount)
    auto update_receiver = sqlgen::update<Account>()
        .set("balance"_c = "balance"_c + amount)
        .where("account_id"_c == to_account_id);

    auto receiver_update_result = conn.execute(update_receiver);
    if (!receiver_update_result) {
      return receiver_update_result.error();
    }

    return true;
  });

  return transaction_result.has_value() && transaction_result.value();
}

}  // namespace transaction_transfer_funds
```

