#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

int update_order_status() {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) return 0;
  create_table<Order>(conn);
  auto res = exec(conn, "UPDATE \"Order\" SET status = 'expired' "
                        "WHERE status = 'pending' AND order_date < DATE('now','-7 days');");
  if (!res) return 0;
  return 1;
}

}  // namespace update_order_status

