```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string username1;
  std::string username2;
  int mutual_friends_count;
};

struct UserFriendCount {
  std::string username;
  int friend_count;
};

struct FriendOfFriend {
  std::string user_name;
  std::string friend_of_friend_name;
  std::string mutual_friend_name;
};

struct SameCityNonFriends {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  std::vector<FriendConnection> results;

  try {
    // Connect to SQLite database
    auto credentials = Credentials{"test_db.sqlite"};
    auto connection = connect(credentials);

    // Create User table
    execute(connection, CreateTable<User>{});

    // Create Friendship table
    execute(connection, CreateTable<Friendship>{});

    // Insert users
    for (const auto& user : users) {
      execute(connection, Insert<User>{user});
    }

    // Insert friendships
    for (const auto& friendship : friendships) {
      execute(connection, Insert<Friendship>{friendship});
    }

    // 1. Use SELF-JOIN to find mutual friends
    auto mutual_friends_query = R"(
      SELECT u1.username, u2.username, COUNT(f1.user_id2) as mutual_friends
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u2 ON f2.user_id2 = u2.user_id
      WHERE u1.user_id < u2.user_id
        AND EXISTS (
          SELECT 1 FROM Friendship f3 
          WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(f1.user_id2) > 0
    )";

    auto mutual_friends = query<MutualFriendsResult>(connection, mutual_friends_query);
    std::cout << "Mutual Friends Analysis:" << std::endl;
    for (const auto& mf : mutual_friends) {
      std::cout << mf.username1 << " and " << mf.username2 
                << " have " << mf.mutual_friends_count << " mutual friends" << std::endl;
    }

    // 2. Use nested query to find users with more than average friends
    auto popular_users_query = R"(
      SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count) 
        FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
      )
      ORDER BY friend_count DESC
    )";

    auto popular_users = query<UserFriendCount>(connection, popular_users_query);
    std::cout << "\nUsers with above-average friends:" << std::endl;
    for (const auto& user : popular_users) {
      std::cout << user.username << " has " << user.friend_count << " friends" << std::endl;
    }

    // 3. Find friend-of-friend relationships
    auto friend_of_friend_query = R"(
      SELECT u1.username as user_name, u3.username as fof_name, u2.username as mutual_friend
      FROM Friendship f1
      INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
      INNER JOIN User u1 ON f1.user_id1 = u1.user_id
      INNER JOIN User u2 ON f1.user_id2 = u2.user_id
      INNER JOIN User u3 ON f2.user_id2 = u3.user_id
      WHERE u1.user_id != u3.user_id
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f3 
          WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
        )
    )";

    auto fof_relationships = query<FriendOfFriend>(connection, friend_of_friend_query);
    std::cout << "\nFriend-of-Friend Relationships:" << std::endl;
    for (const auto& fof : fof_relationships) {
      std::cout << fof.user_name << " is connected to " << fof.friend_of_friend_name 
                << " through " << fof.mutual_friend << std::endl;
    }

    // 4. Count friends per user and identify most connected users
    auto friend_count_query = R"(
      SELECT u.username, COUNT(f.user_id2) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user_id1
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC
    )";

    auto friend_counts = query<UserFriendCount>(connection, friend_count_query);
    std::cout << "\nFriend Counts (Most Connected First):" << std::endl;
    for (const auto& fc : friend_counts) {
      std::cout << fc.username << ": " << fc.friend_count << " friends" << std::endl;
    }

    // 5. Find users in the same city who are not yet friends (recommendation)
    auto same_city_query = R"(
      SELECT u1.username as user1, u2.username as user2, u1.city
      FROM User u1
      INNER JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
      WHERE NOT EXISTS (
        SELECT 1 FROM Friendship f 
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
      AND u1.city IS NOT NULL AND u1.city != ''
    )";

    auto same_city_non_friends = query<SameCityNonFriends>(connection, same_city_query);
    std::cout << "\nSame City Non-Friends (Recommendations):" << std::endl;
    for (const auto& sc : same_city_non_friends) {
      std::cout << sc.user1_name << " and " << sc.user2_name 
                << " both live in " << sc.city << " but are not friends" << std::endl;
    }

    // Return friend connections for the main result
    for (const auto& fof : fof_relationships) {
      results.push_back(FriendConnection{fof.user_name, fof.friend_of_friend_name});
    }

  } catch (const std::exception& e) {
    std::cerr << "Database error: " << e.what() << std::endl;
  }

  return results;
}

}  // namespace analyze_social_network
```

