#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a temporary SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = conn_result.value();

  // Create Product table if it doesn't exist
  auto create_result = conn.and_then(create_table<Product> | if_not_exists);
  if (!create_result) {
    return {};
  }
  conn = create_result.value();

  // Insert products into the table
  auto write_result = sqlgen::write(conn, products);
  if (!write_result) {
    return {};
  }
  conn = write_result.value();

  // Build the mathematical operations query using sqlgen's DSL
  auto query_result = conn.and_then([](auto conn) {
    return sqlgen::read<std::vector<MathAnalysis>>(conn, 
      select(
        "product_id"_c, 
        "name"_c,
        abs("price"_c).as("abs_price"),
        ceil("price"_c).as("ceil_price"), 
        floor("price"_c).as("floor_price"),
        round("price"_c, 2).as("rounded_price"),
        exp("discount_rate"_c / 100).as("exp_discount"),
        ln("price"_c).as("ln_price"),
        log2("quantity"_c).as("log2_quantity"),
        sin("discount_rate"_c).as("sin_discount"),
        cos("discount_rate"_c).as("cos_discount"),
        tan("discount_rate"_c).as("tan_discount"),
        sqrt("quantity"_c).as("sqrt_quantity")
      )
    );
  });

  if (query_result) {
    return query_result.value();
  }

  return {};
}

}  // namespace mathematical_operations_analysis
```

