```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // Create temporary table for OrderItem
  sqlgen::execute(conn, create_table<OrderItem> | if_not_exists).value();

  // Insert the provided items
  sqlgen::write(conn, items).value();

  // Build the SQL query with arithmetic operations
  auto query = select(columns(
    &OrderItem::item_id,
    &OrderItem::order_id,
    &OrderItem::product_id,
    &OrderItem::unit_price,
    &OrderItem::quantity,
    coalesce(&OrderItem::discount_rate, 0.0).as("discount_rate"),
    coalesce(&OrderItem::tax_rate, 0.0).as("tax_rate"),
    (&OrderItem::unit_price * &OrderItem::quantity).as("gross_total"),
    (&OrderItem::unit_price * &OrderItem::quantity * (1 - coalesce(&OrderItem::discount_rate, 0.0)/100)).as("discounted_total"),
    (&OrderItem::unit_price * &OrderItem::quantity * (1 - coalesce(&OrderItem::discount_rate, 0.0)/100) * (1 + coalesce(&OrderItem::tax_rate, 0.0)/100)).as("final_total"),
    (&OrderItem::unit_price * &OrderItem::quantity / &OrderItem::quantity).as("unit_cost"),
    (&OrderItem::quantity % 10).as("quantity_group"),
    (&OrderItem::unit_price * 0.3).as("estimated_profit")
  ));

  // Execute the query and return results
  return sqlgen::read<std::vector<OrderMetrics>>(conn, query).value();
}

}  // namespace calculate_order_metrics
```

