 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Create database connection
  auto db = sqlgen::sqlite::Database::create("test_db.sqlite");

  // Build the join query using sqlgen's query builder
  auto query = sqlgen::Select{
      sqlgen::columns(
          &Order::order_id, 
          &Customer::name, 
          &Payment::amount
      ),
      sqlgen::from<Order>(),
      sqlgen::join<Customer>(sqlgen::on(&Order::customer_id, &Customer::customer_id)),
      sqlgen::join<Payment>(sqlgen::on(&Order::order_id, &Payment::order_id)),
      sqlgen::order_by(&Payment::amount, sqlgen::desc)
  };

  // Execute the query and return results
  return sqlgen::sqlite::query<Consolidated>(db, query);
}

}  // namespace join_orders_customers_payments
