Here's the complete implementation of the function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  // Replace "foo" with "bar" in the content column using SQL REPLACE function
  auto update_result = conn->execute(
    "UPDATE Notes SET content = REPLACE(content, 'foo', 'bar')"
  );

  if (!update_result) {
    throw std::runtime_error("Failed to update notes");
  }

  // Read the updated notes and return them
  auto updated_notes = sqlgen::read<std::vector<Note>>(*conn);
  if (!updated_notes) {
    throw std::runtime_error("Failed to read updated notes");
  }

  // Convert Note objects to UpdatedNote objects
  std::vector<UpdatedNote> result;
  for (const auto& note : *updated_notes) {
    result.push_back(UpdatedNote{note.note_id, note.content});
  }

  return result;
}

}  // namespace replace_text_in_notes
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Performs the text replacement** using a SQL `UPDATE` statement with the `REPLACE()` function to change "foo" to "bar" in the content column
3. **Reads the updated notes** using `sqlgen::read<std::vector<Note>>()`
4. **Converts and returns** the results as `std::vector<UpdatedNote>`

The function uses SQLite's built-in `REPLACE()` function for efficient string replacement directly in the database, rather than fetching, processing, and updating each record individually. This approach is more efficient for large datasets.

