      {.child_id = 2, .parent_id = 1, .note = "Second Child"},
      {.child_id = 3, .parent_id = 1, .note = "Third Child"}
  };

  insert(conn, parent);
  insert(conn, children);

  auto children_before = sqlgen::read<std::vector<Child>>(conn).value();
  EXPECT_EQ(children_before.size(), 3);

