namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // 1. Create Account table
    conn.and_then(create_table<Account> | if_not_exists).value();

    // Insert some initial test data
    std::vector<Account> initial_accounts = {
        Account{.account_id = 1, .balance = 1000.0, .status = "active"},
        Account{.account_id = 2, .balance = 500.0, .status = "inactive"},
        Account{.account_id = 3, .balance = 2500.0, .status = "active"}
    };

    conn.and_then(insert(initial_accounts)).value();

    // 2. Update balances and statuses using set(...) operations
    // Update balance for account_id = 1
    conn.and_then(update<Account>(set("balance"_c = 1500.0), 
                                  where("account_id"_c = 1))).value();

    // Update status for account_id = 2
    conn.and_then(update<Account>(set("status"_c = "active"), 
                                  where("account_id"_c = 2))).value();

    // Update both balance and status for account_id = 3
    conn.and_then(update<Account>(set("balance"_c = 3000.0, "status"_c = "premium"), 
                                  where("account_id"_c = 3))).value();

    // 3. Verify changes persisted
    auto updated_accounts = conn.and_then(read<std::vector<Account>>).value();

    bool verification_passed = true;

    // Check each account to verify the updates
    for (const auto& account : updated_accounts) {
      if (account.account_id == 1) {
        if (account.balance != 1500.0) {
          verification_passed = false;
          break;
        }
      } else if (account.account_id == 2) {
        if (account.status != "active") {
          verification_passed = false;
          break;
        }
      } else if (account.account_id == 3) {
        if (account.balance != 3000.0 || account.status != "premium") {
          verification_passed = false;
          break;
        }
      }
    }

    return verification_passed;

  } catch (const std::exception& e) {
    // Log error or handle exception as needed
    return false;
  }
}

}  // namespace update_set_operations
