Looking at the code fragments and the requirements, I need to implement a FULL JOIN between suppliers and products. Since SQLite doesn't directly support FULL JOIN, I'll need to simulate it using a UNION of LEFT JOIN and RIGHT JOIN. Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = std::move(conn_result).value();

  // Since SQLite doesn't support FULL JOIN directly, we simulate it with UNION of LEFT and RIGHT JOIN
  // First part: LEFT JOIN (all suppliers with their products)
  auto left_join_query = 
    select(columns("s.name"_c.as("supplier_name"), "p.name"_c.as("product_name")))
    .from<Supplier>("s")
    .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

  // Second part: RIGHT JOIN simulated by swapping tables in LEFT JOIN
  // (products without suppliers)
  auto right_join_query = 
    select(columns("s.name"_c.as("supplier_name"), "p.name"_c.as("product_name")))
    .from<Product>("p")
    .left_join<Supplier>("s").on("p.supplier_id"_c == "s.supplier_id"_c)
    .where("s.supplier_id"_c.is_null());

  // Combine both parts with UNION
  auto full_join_query = left_join_query.union_(right_join_query);

  // Execute the query and return results
  auto result = conn.and_then(full_join_query)
                 .and_then(read<std::vector<SupProd>>);

  if (result) {
    return std::move(result).value();
  }

  return {};
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Simulates FULL JOIN** by combining:
   - A **LEFT JOIN** to get all suppliers with their products (including suppliers without products)
   - A **RIGHT JOIN** (simulated by swapping tables in a LEFT JOIN) to get products without suppliers
   - Uses **UNION** to combine both result sets
3. **Returns the joined results** as a vector of `SupProd` structs containing supplier names and optional product names
4. **Handles errors gracefully** by returning an empty vector if any operation fails

The query ensures that all suppliers and all products are included in the result, with `std::optional<std::string>` used for product names to handle cases where a supplier has no products or a product has no supplier.

