```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create tables if they don't exist
  conn.and_then(create_table<Department> | if_not_exists).value();
  conn.and_then(create_table<Employee> | if_not_exists).value();

  // Clear existing data
  conn.and_then("DELETE FROM Department"_sql).value();
  conn.and_then("DELETE FROM Employee"_sql).value();

  // Insert department data
  for (const auto& dept : depts) {
    conn.and_then(insert_into<Department>(dept)).value();
  }

  // Insert employee data
  for (const auto& emp : emps) {
    conn.and_then(insert_into<Employee>(emp)).value();
  }

  // 1. INNER JOIN: Employees with assigned departments
  auto inner_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "INNER JOIN Employee e ON d.department_id = e.department_id"_sql;

  auto inner_results = conn.and_then(inner_join_query)
                         .and_then(read<std::vector<JoinResult>>)
                         .value();
  analysis.inner_join_results = std::move(inner_results);

  // 2. LEFT JOIN: All employees (even without departments)
  auto left_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id"_sql;

  auto left_results = conn.and_then(left_join_query)
                        .and_then(read<std::vector<JoinResult>>)
                        .value();
  analysis.left_join_results = std::move(left_results);

  // 3. RIGHT JOIN: All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we simulate it with LEFT JOIN
  auto right_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "LEFT JOIN Employee e ON d.department_id = e.department_id"_sql;

  auto right_results = conn.and_then(right_join_query)
                         .and_then(read<std::vector<JoinResult>>)
                         .value();
  analysis.right_join_results = std::move(right_results);

  // 4. FULL JOIN: All employees and departments
  // SQLite doesn't support FULL JOIN directly, so we simulate it with UNION of LEFT and RIGHT joins
  auto full_join_query = 
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Employee e "
    "LEFT JOIN Department d ON e.department_id = d.department_id "
    "UNION "
    "SELECT d.department_name, e.first_name, e.last_name, e.salary "
    "FROM Department d "
    "LEFT JOIN Employee e ON d.department_id = e.department_id"_sql;

  auto full_results = conn.and_then(full_join_query)
                       .and_then(read<std::vector<JoinResult>>)
                       .value();
  analysis.full_join_results = std::move(full_results);

  return analysis;
}

}  // namespace analyze_department_employees
```

Key implementation details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database.

2. **Table Creation**: Creates Department and Employee tables using `create_table` with `if_not_exists` modifier.

3. **Data Insertion**: Inserts the provided department and employee data using `insert_into`.

4. **Join Operations**:
   - **INNER JOIN**: Gets employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even without departments)
   - **RIGHT JOIN**: Simulated using LEFT JOIN since SQLite doesn't support RIGHT JOIN directly
   - **FULL JOIN**: Simulated using UNION of LEFT and RIGHT JOINs since SQLite doesn't support FULL JOIN directly

5. **Result Mapping**: Uses `read<std::vector<JoinResult>>` to map SQL results to C++ structs with optional fields to handle NULL values from outer joins.

The function returns a comprehensive `JoinAnalysis` object containing the results of all four join types, allowing for analysis of employee distribution across departments.

