```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Build query to extract weekday and aggregate quantities
  auto query = sqlgen::select(
    sqlgen::as("weekday", sqlgen::expr("strftime('%w', sale_time)")),
    sqlgen::as("total_quantity", sqlgen::sum(Sales::quantity))
  ).from<Sales>().group_by(sqlgen::expr("strftime('%w', sale_time)"));

  // Execute query and return results
  return db.query<WeekdayStats>(query);
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Extracts the weekday** from the `sale_time` timestamp using SQLite's `strftime('%w', sale_time)` function, which returns 0-6 (Sunday-Saturday)
3. **Aggregates totals per weekday** using `sqlgen::sum(Sales::quantity)` grouped by the weekday
4. **Returns the results** as a `std::vector<WeekdayStats>` where each element contains the weekday number and total quantity sold

The query uses SQLite's `strftime` function with the `%w` format specifier to extract the day of the week as a number (0=Sunday, 6=Saturday), then groups and sums the quantities accordingly.

